        var currentSyncPoint: com.omnifret.gplayer.synth.BackingTrackSyncPoint = syncPoints[(syncPointIndex).toInt()]
        var timeDiff: Double = paramtimePosition - currentSyncPoint.synthTime
        var backingTrackPos: Double
        if (syncPointIndex + 1.0 < syncPoints.length)
        {
            var nextSyncPoint: com.omnifret.gplayer.synth.BackingTrackSyncPoint = syncPoints[(syncPointIndex + 1.0).toInt()]
            var relativeNotationTimeDiff: Double = timeDiff / (nextSyncPoint.synthTime - currentSyncPoint.synthTime)
            var backingTrackDiff: Double = nextSyncPoint.syncTime - currentSyncPoint.syncTime
            backingTrackPos = currentSyncPoint.syncTime + backingTrackDiff * relativeNotationTimeDiff
        }
        else 
        {
            var relativeNotationTimeDiff: Double = timeDiff / (mainState.endTime - currentSyncPoint.synthTime)
            var frameDiff: Double = backingTrackLength - currentSyncPoint.syncTime
            backingTrackPos = currentSyncPoint.syncTime + frameDiff * relativeNotationTimeDiff
        }
        return backingTrackPos
    }
    
    /**
     */
    private fun _tickPositionToTimePositionWithSpeed(state: com.omnifret.gplayer.synth.MidiSequencerState, tickPosition: Double, playbackSpeed: Double): Double{
        var paramtickPosition = tickPosition
        var timePosition: Double = 0.0
        var bpm: Double = 120.0
        var lastChange: Double = 0.0
        for (c in state.tempoChanges)
        {
            if (paramtickPosition < c.ticks)
            {
                break
            }
            timePosition = c.time
            bpm = c.bpm
            lastChange = c.ticks
        }
        paramtickPosition -= lastChange
        timePosition += paramtickPosition * ((60000.0).toDouble() / (bpm * state.division))
        return timePosition / playbackSpeed
    }
    
    private val _internalEndTime: Double
    get(){
        if (this.isPlayingMain)
        {
            return if(!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.mainPlaybackRange)))  this._currentState.endTime else this._currentState.playbackRangeEndTime
        }
        return this._currentState.endTime
    }
    
    public val isFinished: Boolean
    get(){
        return this._currentState.currentTime >= this._internalEndTime
    }
    
    public fun stop(): Unit{
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(this.isPlayingMain && com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.mainPlaybackRange))))
        {
            this._currentState.currentTime = this.mainPlaybackRange!!.startTick
        }
        else 
        {
            this._currentState.currentTime = 0.0
        }
        this._currentState.eventIndex = 0.0
    }
    
    public fun resetOneTimeMidi(): Unit{
        this._oneTimeState = null
        this._currentState = this._mainState
    }
    
    public fun resetCountIn(): Unit{
        this._countInState = null
        this._currentState = this._mainState
    }
    
    public fun startCountIn(): Unit{
        this.generateCountInMidi()
        this._currentState = this._countInState!!
        this.stop()
        this._synthesizer.noteOffAll(true)
    }
    
    public fun generateCountInMidi(): Unit{
        var state: com.omnifret.gplayer.synth.MidiSequencerState = com.omnifret.gplayer.synth.MidiSequencerState()
        state.division = this._mainState.division
        var bpm: Double = 120.0
        var timeSignatureNumerator: Double = 4.0
        var timeSignatureDenominator: Double = 4.0
        if (this._mainState.eventIndex == 0.0)
        {
            bpm = this._mainState.tempoChanges[(0).toInt()].bpm
            timeSignatureNumerator = this._mainState.firstTimeSignatureNumerator
            timeSignatureDenominator = this._mainState.firstTimeSignatureDenominator
        }
        else 
        {
            bpm = this._synthesizer.currentTempo
            timeSignatureNumerator = this._synthesizer.timeSignatureNumerator
            timeSignatureDenominator = this._synthesizer.timeSignatureDenominator
        }
        state.tempoChanges.push(com.omnifret.gplayer.synth.MidiFileSequencerTempoChange(bpm, 0.0, 0.0))
        var metronomeLengthInTicks: Double = (((state.division * ((4.0).toDouble() / timeSignatureDenominator))).toInt() or 0).toDouble()
        var metronomeLengthInMillis: Double = metronomeLengthInTicks * ((60000.0).toDouble() / (bpm * this._mainState.division))
        var metronomeTick: Double = 0.0
        var metronomeTime: Double = 0.0
        if (true) {
            var i: Double = 0.0
            
            while(i < timeSignatureNumerator){
                var metronome: com.omnifret.gplayer.synth.synthesis.SynthEvent = com.omnifret.gplayer.synth.synthesis.SynthEvent.newMetronomeEvent(state.synthData.length, metronomeTick, i, metronomeLengthInTicks, metronomeLengthInMillis)
                state.synthData.push(metronome)
                metronome.time = metronomeTime
                metronomeTick += metronomeLengthInTicks
                metronomeTime += metronomeLengthInMillis
                i++
            }
        }
        state.synthData.sort(fun(a: com.omnifret.gplayer.synth.synthesis.SynthEvent, b: com.omnifret.gplayer.synth.synthesis.SynthEvent): Double{
            if (a.time > b.time)
            {
                return 1.0
            }
            if (a.time < b.time)
            {
                return -1.0
            }
            return a.eventIndex - b.eventIndex
        }
        )
        state.endTime = metronomeTime
        state.endTick = metronomeTick
        state.currentTempo = bpm
        state.syncPointTempo = bpm
        this._countInState = state
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _sanitizeBpm(bpm: Double): Double{
            return com.omnifret.gplayer.core.ecmaScript.Math.max(bpm, 1.0)
        }
        
    }
}

